/**
 * Footer Editor Page
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Save, Plus, Trash2, GripVertical, ArrowLeft } from 'lucide-react';

interface FooterLink {
  label: string;
  url: string;
}

interface FooterColumn {
  id: string;
  title: string;
  links: FooterLink[];
}

interface SocialLink {
  platform: 'twitter' | 'linkedin' | 'facebook' | 'instagram' | 'youtube' | 'github';
  url: string;
}

interface FooterData {
  language: string;
  companyName: string;
  tagline: string;
  description: string;
  contactInfo: {
    show: boolean;
    email: string;
    phone: string;
    address: string;
  };
  columns: FooterColumn[];
  bottomBar: {
    show: boolean;
    copyrightText: string;
    showSocialLinks: boolean;
    socialLinks: SocialLink[];
  };
  style: {
    backgroundColor: string;
    textColor: string;
    linkColor: string;
    borderColor: string;
    padding: string;
  };
  isActive: boolean;
}

const languageFlags: Record<string, string> = {
  en: '🇺🇸',
  ar: '🇸🇦',
  tr: '🇹🇷',
  fr: '🇫🇷',
  de: '🇩🇪',
  es: '🇪🇸'
};

const languageNames: Record<string, string> = {
  en: 'English',
  ar: 'العربية',
  tr: 'Türkçe',
  fr: 'Français',
  de: 'Deutsch',
  es: 'Español'
};

const defaultFooterData: FooterData = {
  language: 'en',
  companyName: 'Company Name',
  tagline: 'Your tagline here',
  description: 'Brief description of your company',
  contactInfo: {
    show: true,
    email: '',
    phone: '',
    address: ''
  },
  columns: [
    {
      id: 'col-1',
      title: 'Product',
      links: [
        { label: 'Features', url: '/features' },
        { label: 'Pricing', url: '/pricing' }
      ]
    }
  ],
  bottomBar: {
    show: true,
    copyrightText: '© {year} Company. All rights reserved.',
    showSocialLinks: true,
    socialLinks: []
  },
  style: {
    backgroundColor: '',
    textColor: '',
    linkColor: '',
    borderColor: '',
    padding: 'py-12'
  },
  isActive: true
};

export default function FooterEditorPage() {
  const params = useParams();
  const router = useRouter();
  const [footerData, setFooterData] = useState<FooterData>(defaultFooterData);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const isNew = !params.id || params.id === 'new';

  useEffect(() => {
    if (!isNew) {
      fetchFooter();
    } else {
      setLoading(false);
    }
  }, [params.id]);

  const fetchFooter = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await fetch(`/api/admin/footers/${params.id}`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      if (response.ok) {
        const data = await response.json();
        setFooterData(data.footer);
      }
    } catch (error) {
      console.error('Failed to fetch footer:', error);
    } finally {
      setLoading(false);
    }
  };

  const saveFooter = async () => {
    setSaving(true);
    try {
      const token = localStorage.getItem('adminToken');
      const url = isNew ? '/api/admin/footers' : `/api/admin/footers/${params.id}`;
      const method = isNew ? 'POST' : 'PUT';

      const response = await fetch(url, {
        method,
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(footerData),
      });

      if (response.ok) {
        alert('✅ Footer saved successfully!');
        if (isNew) {
          router.push('/admin/footers');
        }
      } else {
        const data = await response.json();
        alert(`❌ ${data.error || 'Failed to save footer'}`);
      }
    } catch (error) {
      console.error('Failed to save footer:', error);
      alert('❌ Failed to save footer');
    } finally {
      setSaving(false);
    }
  };

  const addColumn = () => {
    setFooterData({
      ...footerData,
      columns: [
        ...footerData.columns,
        {
          id: `col-${Date.now()}`,
          title: 'New Column',
          links: []
        }
      ]
    });
  };

  const updateColumn = (index: number, updates: Partial<FooterColumn>) => {
    const newColumns = [...footerData.columns];
    newColumns[index] = { ...newColumns[index], ...updates };
    setFooterData({ ...footerData, columns: newColumns });
  };

  const deleteColumn = (index: number) => {
    setFooterData({
      ...footerData,
      columns: footerData.columns.filter((_, i) => i !== index)
    });
  };

  const addLink = (columnIndex: number) => {
    const newColumns = [...footerData.columns];
    newColumns[columnIndex].links.push({ label: '', url: '' });
    setFooterData({ ...footerData, columns: newColumns });
  };

  const updateLink = (columnIndex: number, linkIndex: number, updates: Partial<FooterLink>) => {
    const newColumns = [...footerData.columns];
    newColumns[columnIndex].links[linkIndex] = {
      ...newColumns[columnIndex].links[linkIndex],
      ...updates
    };
    setFooterData({ ...footerData, columns: newColumns });
  };

  const deleteLink = (columnIndex: number, linkIndex: number) => {
    const newColumns = [...footerData.columns];
    newColumns[columnIndex].links = newColumns[columnIndex].links.filter((_, i) => i !== linkIndex);
    setFooterData({ ...footerData, columns: newColumns });
  };

  const addSocialLink = () => {
    setFooterData({
      ...footerData,
      bottomBar: {
        ...footerData.bottomBar,
        socialLinks: [
          ...footerData.bottomBar.socialLinks,
          { platform: 'linkedin', url: '' }
        ]
      }
    });
  };

  const updateSocialLink = (index: number, updates: Partial<SocialLink>) => {
    const newSocialLinks = [...footerData.bottomBar.socialLinks];
    newSocialLinks[index] = { ...newSocialLinks[index], ...updates };
    setFooterData({
      ...footerData,
      bottomBar: { ...footerData.bottomBar, socialLinks: newSocialLinks }
    });
  };

  const deleteSocialLink = (index: number) => {
    setFooterData({
      ...footerData,
      bottomBar: {
        ...footerData.bottomBar,
        socialLinks: footerData.bottomBar.socialLinks.filter((_, i) => i !== index)
      }
    });
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto pb-12">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <button
            onClick={() => router.push('/admin/footers')}
            className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
              {isNew ? 'Create Footer' : 'Edit Footer'}
            </h1>
            <p className="text-gray-600 dark:text-gray-400 mt-1">
              {languageFlags[footerData.language]} {languageNames[footerData.language]}
            </p>
          </div>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => router.push('/admin/footers')}
            className="px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
          >
            Cancel
          </button>
          <button
            onClick={saveFooter}
            disabled={saving}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:bg-gray-400 flex items-center gap-2"
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save Footer'}
          </button>
        </div>
      </div>

      <div className="space-y-6">
        {/* Language Selection (only for new) */}
        {isNew && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
            <h2 className="text-xl font-semibold mb-4">Language</h2>
            <select
              value={footerData.language}
              onChange={(e) => setFooterData({ ...footerData, language: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
            >
              {Object.entries(languageNames).map(([code, name]) => (
                <option key={code} value={code}>
                  {languageFlags[code]} {name}
                </option>
              ))}
            </select>
          </div>
        )}

        {/* Brand Info */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
          <h2 className="text-xl font-semibold mb-4">Brand Information</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium mb-2">Company Name *</label>
              <input
                type="text"
                value={footerData.companyName}
                onChange={(e) => setFooterData({ ...footerData, companyName: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Tagline</label>
              <input
                type="text"
                value={footerData.tagline}
                onChange={(e) => setFooterData({ ...footerData, tagline: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Description</label>
              <textarea
                value={footerData.description}
                onChange={(e) => setFooterData({ ...footerData, description: e.target.value })}
                rows={3}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              />
            </div>
          </div>
        </div>

        {/* Contact Info */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-semibold">Contact Information</h2>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={footerData.contactInfo.show}
                onChange={(e) => setFooterData({
                  ...footerData,
                  contactInfo: { ...footerData.contactInfo, show: e.target.checked }
                })}
                className="w-4 h-4"
              />
              <span className="text-sm">Show</span>
            </label>
          </div>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium mb-2">Email</label>
              <input
                type="email"
                value={footerData.contactInfo.email}
                onChange={(e) => setFooterData({
                  ...footerData,
                  contactInfo: { ...footerData.contactInfo, email: e.target.value }
                })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Phone</label>
              <input
                type="tel"
                value={footerData.contactInfo.phone}
                onChange={(e) => setFooterData({
                  ...footerData,
                  contactInfo: { ...footerData.contactInfo, phone: e.target.value }
                })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Address</label>
              <textarea
                value={footerData.contactInfo.address}
                onChange={(e) => setFooterData({
                  ...footerData,
                  contactInfo: { ...footerData.contactInfo, address: e.target.value }
                })}
                rows={2}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              />
            </div>
          </div>
        </div>

        {/* Link Columns */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-semibold">Link Columns</h2>
            <button
              onClick={addColumn}
              className="px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2 text-sm"
            >
              <Plus className="w-4 h-4" />
              Add Column
            </button>
          </div>
          <div className="space-y-4">
            {footerData.columns.map((column, colIdx) => (
              <div key={column.id} className="border border-gray-200 dark:border-gray-700 rounded-lg p-4">
                <div className="flex items-center gap-2 mb-3">
                  <GripVertical className="w-4 h-4 text-gray-400" />
                  <input
                    type="text"
                    value={column.title}
                    onChange={(e) => updateColumn(colIdx, { title: e.target.value })}
                    className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white font-medium"
                    placeholder="Column Title"
                  />
                  <button
                    onClick={() => deleteColumn(colIdx)}
                    className="p-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
                <div className="ml-6 space-y-2">
                  {column.links.map((link, linkIdx) => (
                    <div key={linkIdx} className="flex items-center gap-2">
                      <input
                        type="text"
                        value={link.label}
                        onChange={(e) => updateLink(colIdx, linkIdx, { label: e.target.value })}
                        placeholder="Link Label"
                        className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                      />
                      <input
                        type="text"
                        value={link.url}
                        onChange={(e) => updateLink(colIdx, linkIdx, { url: e.target.value })}
                        placeholder="/url"
                        className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                      />
                      <button
                        onClick={() => deleteLink(colIdx, linkIdx)}
                        className="p-2 text-red-400 hover:text-red-600"
                      >
                        <Trash2 className="w-3 h-3" />
                      </button>
                    </div>
                  ))}
                  <button
                    onClick={() => addLink(colIdx)}
                    className="text-sm text-blue-600 hover:text-blue-700"
                  >
                    + Add Link
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-semibold">Bottom Bar</h2>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={footerData.bottomBar.show}
                onChange={(e) => setFooterData({
                  ...footerData,
                  bottomBar: { ...footerData.bottomBar, show: e.target.checked }
                })}
                className="w-4 h-4"
              />
              <span className="text-sm">Show</span>
            </label>
          </div>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium mb-2">Copyright Text</label>
              <input
                type="text"
                value={footerData.bottomBar.copyrightText}
                onChange={(e) => setFooterData({
                  ...footerData,
                  bottomBar: { ...footerData.bottomBar, copyrightText: e.target.value }
                })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                placeholder="© {year} Company. All rights reserved."
              />
              <p className="text-xs text-gray-500 mt-1">Use {'{year}'} for dynamic year</p>
            </div>

            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-sm font-medium">Social Links</label>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={footerData.bottomBar.showSocialLinks}
                    onChange={(e) => setFooterData({
                      ...footerData,
                      bottomBar: { ...footerData.bottomBar, showSocialLinks: e.target.checked }
                    })}
                    className="w-4 h-4"
                  />
                  <span className="text-sm">Show</span>
                </label>
              </div>
              <div className="space-y-2">
                {footerData.bottomBar.socialLinks.map((social, idx) => (
                  <div key={idx} className="flex items-center gap-2">
                    <select
                      value={social.platform}
                      onChange={(e) => updateSocialLink(idx, { platform: e.target.value as any })}
                      className="px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                    >
                      {['twitter', 'linkedin', 'facebook', 'instagram', 'youtube', 'github'].map(p => (
                        <option key={p} value={p}>{p.charAt(0).toUpperCase() + p.slice(1)}</option>
                      ))}
                    </select>
                    <input
                      type="url"
                      value={social.url}
                      onChange={(e) => updateSocialLink(idx, { url: e.target.value })}
                      placeholder="https://..."
                      className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                    />
                    <button
                      onClick={() => deleteSocialLink(idx)}
                      className="p-2 text-red-400 hover:text-red-600"
                    >
                      <Trash2 className="w-3 h-3" />
                    </button>
                  </div>
                ))}
                <button
                  onClick={addSocialLink}
                  className="text-sm text-blue-600 hover:text-blue-700"
                >
                  + Add Social Link
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Status */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
          <h2 className="text-xl font-semibold mb-4">Status</h2>
          <label className="flex items-center gap-3 cursor-pointer">
            <input
              type="checkbox"
              checked={footerData.isActive}
              onChange={(e) => setFooterData({ ...footerData, isActive: e.target.checked })}
              className="w-5 h-5"
            />
            <div>
              <div className="font-medium">Active</div>
              <div className="text-sm text-gray-500">
                {footerData.isActive 
                  ? 'This footer is currently active and visible on the website'
                  : 'This footer is inactive and hidden from the website'
                }
              </div>
            </div>
          </label>
        </div>
      </div>
    </div>
  );
}
